import React, { useEffect, useRef, useState, useCallback } from 'react';
import io from 'socket.io-client';
import Peer from 'simple-peer';

// Separate component for remote video - handles stream properly
const RemoteVideo = ({ stream, peerId }) => {
  const videoRef = useRef(null);

  useEffect(() => {
    if (videoRef.current && stream) {
      console.log('🎬 RemoteVideo: Setting stream for peer', peerId?.substring(0, 8));
      videoRef.current.srcObject = stream;
      videoRef.current.play().catch(e => console.log('Autoplay prevented:', e));
    }
    
    // Cleanup
    return () => {
      if (videoRef.current) {
        videoRef.current.srcObject = null;
      }
    };
  }, [stream, peerId]);

  if (!stream) return null;

  return (
    <div className="bg-black rounded-lg overflow-hidden relative aspect-video">
      <video
        ref={videoRef}
        autoPlay
        playsInline
        className="w-full h-full object-cover"
      />
      <div className="absolute bottom-2 left-2 bg-black bg-opacity-50 text-white px-2 py-1 rounded text-xs">
        Peer {peerId ? peerId.substring(0, 8) : 'Unknown'}
      </div>
    </div>
  );
};

const VideoCall = ({ roomId, userId, onLeave, serverUrl }) => {
  const [peers, setPeers] = useState([]);
  const [localStream, setLocalStream] = useState(null);
  const [remoteStreams, setRemoteStreams] = useState(new Map());
  const [isAudioEnabled, setIsAudioEnabled] = useState(true);
  const [isVideoEnabled, setIsVideoEnabled] = useState(true);
  const [connectionStatus, setConnectionStatus] = useState('connecting');
  const [socketId, setSocketId] = useState('');
  const [hasJoinedRoom, setHasJoinedRoom] = useState(false);
  
  const socketRef = useRef();
  const peersRef = useRef([]);
  const localVideoRef = useRef();
  const localStreamRef = useRef(null);
  const remoteVideosRef = useRef(new Map());
  const pendingOffersRef = useRef([]);
  const pendingParticipantsRef = useRef([]);
  const pendingUsersRef = useRef([]);

  // Use useCallback to prevent recreation
  const createPeer = useCallback((targetSocketId, initiator, offer = null) => {
    if (!localStreamRef.current) {
      console.log('⏳ Cannot create peer - no local stream');
      return;
    }

    console.log('🔧 Creating peer for:', targetSocketId, 'initiator:', initiator);

    const peer = new Peer({
      initiator: initiator,
      stream: localStreamRef.current,
      trickle: true,
      config: {
        iceServers: [
          { urls: 'stun:stun.l.google.com:19302' },
          { urls: 'stun:stun1.l.google.com:19302' },
          { urls: 'stun:stun2.l.google.com:19302' },
          { urls: 'stun:stun3.l.google.com:19302' },
          { urls: 'stun:stun4.l.google.com:19302' },
          {
            urls: 'turn:openrelay.metered.ca:80',
            username: 'openrelayproject',
            credential: 'openrelayproject'
          },
          {
            urls: 'turn:openrelay.metered.ca:443',
            username: 'openrelayproject',
            credential: 'openrelayproject'
          }
        ]
      }
    });

    peersRef.current.push({
      peerID: targetSocketId,
      peer: peer
    });

    setPeers(peersRef.current.map(p => p.peerID));

    peer.on('signal', signal => {
      console.log('📡 Signal from peer:', targetSocketId, signal.type);
      
      if (signal.type === 'offer') {
        socketRef.current.emit('offer', {
          offer: signal,
          to: targetSocketId,
          from: socketRef.current.id
        });
      } else if (signal.type === 'answer') {
        socketRef.current.emit('answer', {
          answer: signal,
          to: targetSocketId,
          from: socketRef.current.id
        });
      } else if (signal.type === 'candidate') {
        socketRef.current.emit('ice-candidate', {
          candidate: signal,
          to: targetSocketId,
          from: socketRef.current.id
        });
      }
    });

    peer.on('stream', stream => {
      console.log('🎥✅ GOT STREAM from peer:', targetSocketId);
      console.log('📊 Stream tracks:', stream.getTracks().length);
      console.log('📹 Video tracks:', stream.getVideoTracks().length);
      console.log('🎤 Audio tracks:', stream.getAudioTracks().length);
      
      // Store stream in state
      setRemoteStreams(prev => {
        const newMap = new Map(prev);
        newMap.set(targetSocketId, stream);
        return newMap;
      });
      
      remoteVideosRef.current.set(targetSocketId, stream);
    });

    peer.on('connect', () => {
      console.log('✅ Peer connected with:', targetSocketId);
    });

    peer.on('error', err => {
      console.error('❌ Peer error:', err);
    });

    if (offer) {
      console.log('📨 Signaling offer to peer');
      peer.signal(offer);
    }
  }, []); // Empty deps since it only uses refs

  useEffect(() => {
    console.log('🎬 VideoCall mounted with roomId:', roomId, 'userId:', userId);
    
    socketRef.current = io(serverUrl, {
      transports: ['websocket', 'polling'],
      reconnectionAttempts: 5,
      reconnectionDelay: 1000,
      timeout: 20000,
      forceNew: true
    });

    socketRef.current.on('connect', () => {
      console.log('✅ Socket connected:', socketRef.current.id);
      setSocketId(socketRef.current.id);
      setConnectionStatus('connected');
      
      console.log('📷 Requesting camera access...');
      navigator.mediaDevices.getUserMedia({ 
        video: { 
          width: { ideal: 640 },
          height: { ideal: 480 },
          facingMode: "user"
        }, 
        audio: true 
      })
      .then(stream => {
        console.log('✅ Got local stream');
        console.log('📹 Video tracks:', stream.getVideoTracks().length);
        console.log('🎤 Audio tracks:', stream.getAudioTracks().length);
        
        setLocalStream(stream);
        localStreamRef.current = stream;
        if (localVideoRef.current) {
          localVideoRef.current.srcObject = stream;
        }

        // Process any pending users
        if (pendingUsersRef.current.length > 0) {
          console.log('👥 Connecting to pending users:', pendingUsersRef.current);
          pendingUsersRef.current.forEach(socketId => {
            if (socketId !== socketRef.current.id) {
              createPeer(socketId, false);
            }
          });
          pendingUsersRef.current = [];
        }

        console.log('🚪 Joining room:', roomId);
        socketRef.current.emit('join-room', { roomId, userId });
        setHasJoinedRoom(true);
        
        // Process pending offers
        if (pendingOffersRef.current.length > 0) {
          console.log('📋 Processing pending offers:', pendingOffersRef.current.length);
          pendingOffersRef.current.forEach(({ offer, from }) => {
            createPeer(from, false, offer);
          });
          pendingOffersRef.current = [];
        }

        // Process pending participants
        if (pendingParticipantsRef.current.length > 0) {
          console.log('👥 Processing pending participants:', pendingParticipantsRef.current.length);
          pendingParticipantsRef.current.forEach(participant => {
            if (participant.socketId !== socketRef.current.id) {
              createPeer(participant.socketId, true);
            }
          });
          pendingParticipantsRef.current = [];
        }
      })
      .catch(error => {
        console.error('❌ Camera error:', error);
        setConnectionStatus('error');
        alert(`Camera access failed: ${error.message}`);
      });
    });

    socketRef.current.on('connect_error', (error) => {
      console.error('❌ Socket error:', error);
      setConnectionStatus('error');
    });

    socketRef.current.on('disconnect', (reason) => {
      console.log('Socket disconnected:', reason);
      setConnectionStatus('connecting');
    });

    socketRef.current.on('reconnect', () => {
      console.log('Socket reconnected');
      setConnectionStatus('connected');
    });

    socketRef.current.on('room-joined', ({ participants }) => {
      console.log('🏠 Room joined! Participants:', participants.length);
      
      if (!localStreamRef.current) {
        console.log('⏳ Saving participants for later');
        pendingParticipantsRef.current = participants;
        return;
      }

      participants.forEach(participant => {
        if (participant.socketId !== socketRef.current.id) {
          console.log('👥 Creating peer for existing user:', participant.socketId);
          createPeer(participant.socketId, true);
        }
      });
    });

    socketRef.current.on('user-connected', ({ socketId }) => {
      console.log('👤 User connected:', socketId);
      
      if (!localStreamRef.current) {
        console.log('⏳ Saving user for later');
        pendingUsersRef.current.push(socketId);
        return;
      }
      
      if (socketId !== socketRef.current.id) {
        createPeer(socketId, false);
      }
    });

    socketRef.current.on('offer', ({ offer, from }) => {
      console.log('📞 Received offer from:', from);
      
      if (!localStreamRef.current) {
        console.log('⏳ Queueing offer');
        pendingOffersRef.current.push({ offer, from });
        return;
      }
      
      const peerExists = peersRef.current.find(p => p.peerID === from);
      if (!peerExists) {
        createPeer(from, false, offer);
      }
    });

    socketRef.current.on('answer', ({ answer, from }) => {
      console.log('📞 Received answer from:', from);
      const peer = peersRef.current.find(p => p.peerID === from);
      if (peer) {
        peer.peer.signal(answer);
      }
    });

    socketRef.current.on('ice-candidate', ({ candidate, from }) => {
      console.log('📞 Received ICE from:', from);
      const peer = peersRef.current.find(p => p.peerID === from);
      if (peer && candidate) {
        peer.peer.signal(candidate);
      }
    });

    socketRef.current.on('user-disconnected', ({ socketId }) => {
      console.log('👋 User disconnected:', socketId);
      
      // Remove peer
      const peerIndex = peersRef.current.findIndex(p => p.peerID === socketId);
      if (peerIndex !== -1) {
        peersRef.current[peerIndex].peer.destroy();
        peersRef.current.splice(peerIndex, 1);
      }
      
      // Remove remote stream
      setRemoteStreams(prev => {
        const newMap = new Map(prev);
        newMap.delete(socketId);
        return newMap;
      });
      
      remoteVideosRef.current.delete(socketId);
      setPeers(peersRef.current.map(p => p.peerID));
    });

    socketRef.current.on('error', ({ message }) => {
      console.error('Room error:', message);
      if (message === 'Room not found' || message === 'Room is full') {
        alert(message);
        onLeave();
      }
    });

    // Cleanup
    return () => {
      console.log('🧹 Cleaning up VideoCall');
      
      // Copy refs to local variables for cleanup
      const currentPeers = [...peersRef.current];
      const currentStream = localStream;
      
      currentPeers.forEach(p => p.peer?.destroy());
      
      if (currentStream) {
        currentStream.getTracks().forEach(t => t.stop());
      }
      
      if (socketRef.current) {
        socketRef.current.disconnect();
      }
    };
  }, [roomId, userId, serverUrl, createPeer, onLeave]); // Added proper dependencies

  const toggleAudio = () => {
    if (localStream) {
      localStream.getAudioTracks().forEach(t => t.enabled = !isAudioEnabled);
      setIsAudioEnabled(!isAudioEnabled);
    }
  };

  const toggleVideo = () => {
    if (localStream) {
      localStream.getVideoTracks().forEach(t => t.enabled = !isVideoEnabled);
      setIsVideoEnabled(!isVideoEnabled);
    }
  };

  return (
    <div className="space-y-4">
      {/* Status Bar */}
      <div className="bg-white rounded-lg shadow-md p-4">
        <div className="flex items-center justify-between">
          <div className="flex items-center space-x-4">
            <div className={`h-3 w-3 rounded-full ${
              connectionStatus === 'connected' ? 'bg-green-500' : 
              connectionStatus === 'connecting' ? 'bg-yellow-500' : 'bg-red-500'
            }`} />
            <span className="text-sm font-medium">
              {connectionStatus === 'connected' ? 'Connected' : 
               connectionStatus === 'connecting' ? 'Connecting...' : 'Error'}
            </span>
            <span className="text-sm">Room: {roomId}</span>
            <span className="text-sm">Users: {peers.length + 1}</span>
          </div>
          <button onClick={onLeave} className="bg-red-500 text-white px-4 py-2 rounded">
            Leave Call
          </button>
        </div>
      </div>

      {/* Video Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {/* Local Video */}
        <div className="bg-black rounded-lg overflow-hidden relative aspect-video">
          <video
            ref={localVideoRef}
            autoPlay
            playsInline
            muted
            className="w-full h-full object-cover"
          />
          <div className="absolute bottom-2 left-2 bg-black bg-opacity-50 text-white px-2 py-1 rounded text-xs">
            You {!isVideoEnabled && '(Video Off)'} {!isAudioEnabled && '(Muted)'}
          </div>
        </div>

        {/* Remote Videos - Using the improved RemoteVideo component */}
        {Array.from(remoteStreams.entries()).map(([socketId, stream]) => (
          <RemoteVideo key={socketId} stream={stream} peerId={socketId} />
        ))}

        {/* Placeholder when waiting */}
        {remoteStreams.size === 0 && peers.length > 0 && (
          <div className="bg-gray-800 rounded-lg aspect-video flex items-center justify-center text-gray-400">
            <div className="text-center">
              <p>⏳ Peer connected, waiting for video...</p>
              <p className="text-sm mt-2">Check console for "GOT STREAM" message</p>
            </div>
          </div>
        )}

        {peers.length === 0 && (
          <div className="bg-gray-800 rounded-lg aspect-video flex items-center justify-center text-gray-400">
            <div className="text-center">
              <p>Waiting for others to join...</p>
              <p className="text-sm mt-2">Room ID: {roomId}</p>
            </div>
          </div>
        )}
      </div>

      {/* Controls */}
      <div className="bg-white rounded-lg shadow-md p-4">
        <div className="flex justify-center space-x-4">
          <button onClick={toggleAudio} 
            className={`p-3 rounded-full ${isAudioEnabled ? 'bg-blue-500' : 'bg-red-500'} text-white`}>
            {isAudioEnabled ? '🔊' : '🔇'}
          </button>
          <button onClick={toggleVideo}
            className={`p-3 rounded-full ${isVideoEnabled ? 'bg-blue-500' : 'bg-red-500'} text-white`}>
            {isVideoEnabled ? '📹' : '🚫'}
          </button>
        </div>
      </div>

      {/* Debug Info */}
      {process.env.NODE_ENV === 'development' && (
        <div className="bg-gray-800 text-green-400 p-4 rounded-lg text-xs">
          <div>Socket: {socketId || 'No ID'}</div>
          <div>Status: {connectionStatus}</div>
          <div>Peers: {peers.length}</div>
          <div>Remote Streams: {remoteStreams.size}</div>
          <div>Has Local Stream: {localStream ? '✅' : '❌'}</div>
          <div>Pending: {pendingUsersRef.current.length} users, {pendingOffersRef.current.length} offers</div>
        </div>
      )}
    </div>
  );
};

export default VideoCall;
